code.C:
#include <stdio.h>

int main() {
    int t, num;
    if (scanf("%d", &t) != 1) return 0;
    while (t--) {
        if (scanf("%d", &num) != 1) break;
        if ((num & 1) == 0) {
            printf("Even\n");
        } else {
            printf("Odd\n");
        }
    }
    return 0;
}

